  1	import React, { FC, useMemo } from 'react';
  2	import { useLocation, useNavigate } from 'react-router-dom-v5-compat';
  3	import classNames from 'classnames';
  4	
  5	import {
  6	  VirtualMachineClusterPreferenceModelGroupVersionKind,
  7	  VirtualMachineClusterPreferenceModelRef,
  8	  VirtualMachinePreferenceModelRef,
  9	} from '@kubevirt-ui/kubevirt-api/console';
 10	import { ALL_NAMESPACES_SESSION_KEY } from '@kubevirt-utils/hooks/constants';
 11	import useIsSearchPage from '@kubevirt-utils/hooks/useIsSearchPage';
 12	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 13	import useUserPreferences from '@kubevirt-utils/hooks/useUserPreferences';
 14	import { ListPageProps } from '@kubevirt-utils/utils/types';
 15	import { isEmpty } from '@kubevirt-utils/utils/utils';
 16	import { ListPageHeader } from '@openshift-console/dynamic-plugin-sdk';
 17	import { Tab, Tabs, TabTitleText } from '@patternfly/react-core';
 18	
 19	import PreferenceCreateButton from './components/PreferenceCreateButton';
 20	import ClusterPreferenceList from './ClusterPreferenceList';
 21	import UserPreferenceList from './UserPreferenceList';
 22	
 23	import '@kubevirt-utils/styles/list-managment-group.scss';
 24	
 25	const PreferencePage: FC<ListPageProps> = (props) => {
 26	  const { t } = useKubevirtTranslation();
 27	  const navigate = useNavigate();
 28	  const location = useLocation();
 29	  const activeNamespace = props?.namespace ?? ALL_NAMESPACES_SESSION_KEY;
 30	
 31	  const isSearchPage = useIsSearchPage();
 32	
 33	  const activeTabKey = useMemo(
 34	    () =>
 35	      location?.pathname.includes(VirtualMachineClusterPreferenceModelGroupVersionKind.kind)
 36	        ? 0
 37	        : 1,
 38	    [location?.pathname],
 39	  );
 40	  const [userPreferences, loaded, loadError] = useUserPreferences(
 41	    activeNamespace,
 42	    props?.fieldSelector,
 43	    props?.selector,
 44	  );
 45	
 46	  const urlUserPreference = useMemo(
 47	    () =>
 48	      activeNamespace === ALL_NAMESPACES_SESSION_KEY
 49	        ? `/k8s/all-namespaces/${VirtualMachinePreferenceModelRef}`
 50	        : `/k8s/ns/${activeNamespace}/${VirtualMachinePreferenceModelRef}`,
 51	    [activeNamespace],
 52	  );
 53	
 54	  if (isSearchPage) {
 55	    const searchParams = new URLSearchParams(location?.search);
 56	
 57	    const kindSearched = searchParams.get('kind');
 58	    return kindSearched === VirtualMachineClusterPreferenceModelRef ? (
 59	      <ClusterPreferenceList {...props} />
 60	    ) : (
 61	      <UserPreferenceList {...props} />
 62	    );
 63	  }
 64	
 65	  return (
 66	    <>
 67	      <div className={classNames({ 'list-header-spacer': activeTabKey === 0 })}>
 68	        <ListPageHeader
 69	          title={
 70	            activeTabKey === 0
 71	              ? t('VirtualMachineClusterPreferences')
 72	              : t('VirtualMachinePreferences')
 73	          }
 74	        >
 75	          {(activeTabKey === 0 || (!isEmpty(userPreferences) && loaded && !loadError)) && (
 76	            <PreferenceCreateButton namespace={activeNamespace} />
 77	          )}
 78	        </ListPageHeader>
 79	      </div>
 80	      <Tabs
 81	        onSelect={(_, tabIndex: number | string) => {
 82	          navigate(
 83	            tabIndex === 0
 84	              ? `/k8s/cluster/${VirtualMachineClusterPreferenceModelRef}`
 85	              : urlUserPreference,
 86	          );
 87	        }}
 88	        activeKey={activeTabKey}
 89	        style={{ flexShrink: 0 }}
 90	      >
 91	        <Tab
 92	          title={
 93	            <TabTitleText data-test="cluster-preferences-tab">
 94	              {t('Cluster Preferences')}
 95	            </TabTitleText>
 96	          }
 97	          eventKey={0}
 98	        >
 99	          <ClusterPreferenceList {...props} />
100	        </Tab>
101	        <Tab
102	          title={
103	            <TabTitleText data-test="user-preferences-tab">{t('User Preferences')}</TabTitleText>
104	          }
105	          eventKey={1}
106	        >
107	          <UserPreferenceList {...props} />
108	        </Tab>
109	      </Tabs>
110	    </>
111	  );
112	};
113	
114	export default PreferencePage;

